// MARK: - Keychain Helper
class KeychainManager {
    
    static let shared = KeychainManager()
    private init() {}
    
    private let service = "com.myapp.authentication"
    private let accountKey = "biometricAuthEnabled"
    private let authTokenKey = "authToken"
    
    func setBiometricAuthEnabled(_ enabled: Bool) {
        let data = Data([enabled ? 1 : 0])
        save(data: data, forKey: accountKey)
    }
    
    func isBiometricAuthEnabled() -> Bool {
        guard let data = load(key: accountKey), let firstByte = data.first else {
            return false
        }
        return firstByte == 1
    }
    
    func saveAuthToken(_ token: String) {
        guard let data = token.data(using: .utf8) else { return }
        save(data: data, forKey: authTokenKey)
    }
    
    func loadAuthToken() -> String? {
        guard let data = load(key: authTokenKey) else { return nil }
        return String(data: data, encoding: .utf8)
    }
    
    func clearAll() {
        delete(key: accountKey)
        delete(key: authTokenKey)
    }
    
    private func save(data: Data, forKey key: String) {
        delete(key: key)
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemAdd(query as CFDictionary, nil)
    }
    
    private func load(key: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        SecItemCopyMatching(query as CFDictionary, &result)
        return result as? Data
    }
    
    private func delete(key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - Biometric Auth Manager
class BiometricAuthManager {
    
    static let shared = BiometricAuthManager()
    private init() {}
    
    enum BiometricType {
        case none
        case touchID
        case faceID
    }
    
    enum AuthResult {
        case success
        case failure(Error)
        case biometryNotAvailable
        case biometryNotEnrolled
        case biometryLockout
        case userCancelled
        case userFallback
    }
    
    var biometricType: BiometricType {
        let context = LAContext()
        var error: NSError?
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            return .none
        }
        switch context.biometryType {
        case .touchID:
            return .touchID
        case .faceID:
            return .faceID
        case .opticID:
            return .none
        @unknown default:
            return .none
        }
    }
    
    var biometricTypeString: String {
        switch biometricType {
        case .faceID:
            return "Face ID"
        case .touchID:
            return "Touch ID"
        case .none:
            return "Biometric Authentication"
        }
    }
    
    var isBiometricAvailable: Bool {
        let context = LAContext()
        var error: NSError?
        return context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
    }
    
    func authenticate(reason: String? = nil, completion: @escaping (AuthResult) -> Void) {
        let context = LAContext()
        context.localizedCancelTitle = "Use Password"
        context.localizedFallbackTitle = "Enter Password"
        
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            if let error = error {
                let result = mapLAError(error)
                DispatchQueue.main.async {
                    completion(result)
                }
            } else {
                DispatchQueue.main.async {
                    completion(.biometryNotAvailable)
                }
            }
            return
        }
        
        let authReason = reason ?? "Authenticate with \(biometricTypeString) to access your account"
        
        context.evaluatePolicy(
            .deviceOwnerAuthenticationWithBiometrics,
            localizedReason: authReason
        ) { success, error in
            DispatchQueue.main.async {
                if success {
                    completion(.success)
                } else if let error = error {
                    completion(self.mapLAError(error as NSError))
                } else {
                    completion(.failure(NSError(domain: "BiometricAuth", code: -1, userInfo: [NSLocalizedDescriptionKey: "Unknown error"])))
                }
            }
        }
    }
    
    private func mapLAError(_ error: NSError) -> AuthResult {
        guard let laError = error as? LAError else {
            return .failure(error)
        }
        
        switch laError.code {
        case .authenticationFailed:
            return .failure(laError)
        case .userCancel:
            return .userCancelled
        case .userFallback:
            return .userFallback
        case .biometryNotAvailable:
            return .biometryNotAvailable
        case .biometryNotEnrolled:
            return .biometryNotEnrolled
        case .biometryLockout:
            return .biometryLockout
        default:
            return .failure(laError)
        }
    }
}

// MARK: - Session Manager
class SessionManager {
    
    static let shared = SessionManager()
    private init() {}
    
    private(set) var isAuthenticated: Bool = false
    
    var shouldAttemptBiometricAuth: Bool {
        return KeychainManager.shared.isBiometricAuthEnabled() &&
               KeychainManager.shared.loadAuthToken() != nil &&
               BiometricAuthManager.shared.isBiometricAvailable
    }
    
    func markAuthenticated(withToken token: String, enableBiometric: Bool) {
        isAuthenticated = true
        KeychainManager.shared.saveAuthToken(token)
        if enableBiometric {
            KeychainManager.shared.setBiometricAuthEnabled(true)
        }
    }
    
    func markAuthenticatedViaBiometric() {
        isAuthenticated = true
    }
    
    func logout() {
        isAuthenticated = false
        KeychainManager.shared.clearAll()
    }
    
    func disableBiometric() {
        KeychainManager.shared.setBiometricAuthEnabled(false)
    }
}

