// MARK: - Main (Home) View Controller
class HomeViewController: UIViewController {
    
    var onLogout: (() -> Void)?
    
    private let welcomeLabel = UILabel()
    private let biometricStatusLabel = UILabel()
    private let toggleBiometricButton = UIButton(type: .system)
    private let logoutButton = UIButton(type: .system)
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        navigationItem.title = "Home"
        
        welcomeLabel.text = "You're authenticated! 🎉"
        welcomeLabel.font = UIFont.systemFont(ofSize: 24, weight: .bold)
        welcomeLabel.textAlignment = .center
        welcomeLabel.numberOfLines = 0
        
        biometricStatusLabel.font = UIFont.systemFont(ofSize: 14, weight: .regular)
        biometricStatusLabel.textColor = .secondaryLabel
        biometricStatusLabel.textAlignment = .center
        biometricStatusLabel.numberOfLines = 0
        updateBiometricStatusLabel()
        
        toggleBiometricButton.titleLabel?.font = UIFont.systemFont(ofSize: 16, weight: .medium)
        toggleBiometricButton.addTarget(self, action: #selector(toggleBiometricTapped), for: .touchUpInside)
        updateToggleButton()
        
        logoutButton.setTitle("Sign Out", for: .normal)
        logoutButton.setTitleColor(.systemRed, for: .normal)
        logoutButton.titleLabel?.font = UIFont.systemFont(ofSize: 16, weight: .medium)
        logoutButton.addTarget(self, action: #selector(logoutTapped), for: .touchUpInside)
        
        let stackView = UIStackView(arrangedSubviews: [
            welcomeLabel,
            biometricStatusLabel,
            toggleBiometricButton,
            UIView(),
            logoutButton
        ])
        stackView.axis = .vertical
        stackView.spacing = 20
        stackView.alignment = .center
        stackView.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(stackView)
        NSLayoutConstraint.activate([
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32),
            stackView.centerYAnchor.constraint(equalTo: view.centerYAnchor)
        ])
    }
    
    private func updateBiometricStatusLabel() {
        let biometricName = BiometricAuthManager.shared.biometricTypeString
        let isEnabled = KeychainManager.shared.isBiometricAuthEnabled()
        biometricStatusLabel.text = "\(biometricName) is \(isEnabled ? "enabled ✅" : "disabled ❌")"
    }
    
    private func updateToggleButton() {
        let isEnabled = KeychainManager.shared.isBiometricAuthEnabled()
        let biometricName = BiometricAuthManager.shared.biometricTypeString
        toggleBiometricButton.setTitle(isEnabled ? "Disable \(biometricName)" : "Enable \(biometricName)", for: .normal)
        toggleBiometricButton.isHidden = !BiometricAuthManager.shared.isBiometricAvailable
    }
    
    @objc private func toggleBiometricTapped() {
        let isCurrentlyEnabled = KeychainManager.shared.isBiometricAuthEnabled()
        
        if isCurrentlyEnabled {
            SessionManager.shared.disableBiometric()
            updateBiometricStatusLabel()
            updateToggleButton()
        } else {
            // Verify biometric before enabling
            BiometricAuthManager.shared.authenticate(reason: "Verify your identity to enable biometric login") { [weak self] result in
                switch result {
                case .success:
                    KeychainManager.shared.setBiometricAuthEnabled(true)
                    self?.updateBiometricStatusLabel()
                    self?.updateToggleButton()
                default:
                    let alert = UIAlertController(
                        title: "Failed",
                        message: "Could not verify your identity. Please try again.",
                        preferredStyle: .alert
                    )
                    alert.addAction(UIAlertAction(title: "OK", style: .default))
                    self?.present(alert, animated: true)
                }
            }
        }
    }
    
    @objc private func logoutTapped() {
        let alert = UIAlertController(
            title: "Sign Out",
            message: "Are you sure you want to sign out?",
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Sign Out", style: .destructive) { [weak self] _ in
            SessionManager.shared.logout()
            self?.onLogout?()
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        
        present(alert, animated: true)
    }
}

// MARK: - App Coordinator / Root Navigation
class AppCoordinator {
    
    private let window: UIWindow
    
    init(window: UIWindow) {
        self.window = window
    }
    
    func start() {
        if SessionManager.shared.shouldAttemptBiometricAuth {
            showLogin()
        } else if SessionManager.shared.isAuthenticated {
            showHome()
        } else {
            showLogin()
        }
    }
    
    func showLogin() {
        let loginVC = LoginViewController()
        loginVC.onLoginSuccess = { [weak self] in
            self?.showHome()
        }
        
        let nav = UINavigationController(rootViewController: loginVC)
        window.rootViewController = nav
        window.makeKeyAndVisible()
        
        if window.rootViewController != nil {
            UIView.transition(with: window, duration: 0.3, options: .transitionCrossDissolve, animations: nil)
        }
    }
    
    func showHome() {
        let homeVC = HomeViewController()
        homeVC.onLogout = { [weak self] in
            self?.showLogin()
        }
        
        let nav = UINavigationController(rootViewController: homeVC)
        window.rootViewController = nav
        window.makeKeyAndVisible()
        
        UIView.transition(with: window, duration: 0.3, options: .transitionCrossDissolve, animations: nil)
    }
}

// MARK: - App Delegate
@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    var coordinator: AppCoordinator?
    
    func application(
        _ application: UIApplication,
        didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?
    ) -> Bool {
        
        let window = UIWindow(frame: UIScreen.main.bounds)
        self.window = window
        
        coordinator = AppCoordinator(window: window)
        coordinator?.start()
        
        return true
    }
    
    // Re-authenticate when app comes back to foreground (optional security measure)
    func applicationWillEnterForeground(_ application: UIApplication) {
